import styled, { keyframes, css } from 'styled-components';
import theme from '../../styles/theme';

const spin = keyframes`
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
`;

const pulse = keyframes`
  0%, 100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
`;

const LoadingSpinner = styled.div`
  display: inline-flex;
  align-items: center;
  justify-content: center;

  /* Size variants */
  ${(props) => {
    switch (props.size) {
      case 'small':
        return `
          width: 20px;
          height: 20px;
        `;
      case 'medium':
        return `
          width: 40px;
          height: 40px;
        `;
      case 'large':
        return `
          width: 60px;
          height: 60px;
        `;
      default:
        return `
          width: 40px;
          height: 40px;
        `;
    }
  }}

  /* Spinner types */
  ${(props) => {
    switch (props.type) {
      case 'dots':
        return `
          display: flex;
          gap: 4px;

          &::before,
          &::after {
            content: '';
            width: ${props.size === 'small' ? '6px' : props.size === 'large' ? '12px' : '8px'};
            height: ${props.size === 'small' ? '6px' : props.size === 'large' ? '12px' : '8px'};
            background-color: ${props.color || theme.colors.primary};
            border-radius: 50%;
            animation: ${pulse} 1.4s ease-in-out infinite both;
          }

          &::before {
            animation-delay: -0.32s;
          }

          &::after {
            animation-delay: 0.16s;
          }
        `;
      case 'pulse':
        return `
          background-color: ${props.color || theme.colors.primary};
          border-radius: 50%;
          animation: ${pulse} 1.5s ease-in-out infinite;
        `;
      case 'bars':
        return `
          display: flex;
          gap: 2px;
          align-items: flex-end;

          &::before,
          &::after {
            content: '';
            width: ${props.size === 'small' ? '3px' : props.size === 'large' ? '6px' : '4px'};
            height: 100%;
            background-color: ${props.color || theme.colors.primary};
            animation: ${pulse} 1.2s ease-in-out infinite both;
          }

          &::before {
            animation-delay: -0.24s;
          }

          &::after {
            animation-delay: 0.12s;
          }
        `;
      default:
        return css`
          border: ${props.size === 'small' ? '2px' : props.size === 'large' ? '4px' : '3px'} solid rgba(26, 54, 93, 0.2);
          border-top-color: ${props.color || theme.colors.primary};
          border-radius: 50%;
          animation: ${spin} 0.8s linear infinite;
        `;
    }
  }}

  /* Centered container */
  ${(props) =>
    props.centered &&
    `
      position: fixed;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      z-index: 9999;
    `}

  /* Full screen overlay */
  ${(props) =>
    props.fullScreen &&
    `
      position: fixed;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background-color: rgba(0, 0, 0, 0.5);
      display: flex;
      align-items: center;
      justify-content: center;
      z-index: 9999;
    `}

  /* Inline text */
  ${(props) =>
    props.inline &&
    `
      display: inline-flex;
      vertical-align: middle;
      margin-right: 8px;
    `}
`;

LoadingSpinner.defaultProps = {
  size: 'medium',
  type: 'spinner',
};

export default LoadingSpinner;
